function createOverlayThemeController(root, config, helpers){
  let currentConfig = {...(config || {})};
  let points = [];
  let visibleCount = 0;
  let listEl = null;
  let exitTimer = null;
  const enterTimers = new Set();

  function normalizePoint(item){
    if(!item || typeof item !== 'object') return null;
    const title = String(item.title ?? '').trim();
    const content = String(item.content ?? '').trim();
    if(!title && !content) return null;
    return { title, content };
  }

  function parsePoints(cfg){
    if(Array.isArray(cfg?.points)){
      return cfg.points.map(normalizePoint).filter(Boolean);
    }

    if(Array.isArray(cfg?.points_json)){
      return cfg.points_json.map(normalizePoint).filter(Boolean);
    }

    const raw = String(cfg?.points_json ?? '').trim();
    if(!raw){
      return [];
    }

    try{
      const parsed = JSON.parse(raw);
      if(!Array.isArray(parsed)) return [];
      return parsed.map(normalizePoint).filter(Boolean);
    }catch(_err){
      return [];
    }
  }

  function escapeHtml(value){
    return String(value)
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll('>', '&gt;')
      .replaceAll('\"', '&quot;')
      .replaceAll("'", '&#39;');
  }

  function clearAnimationTimers(){
    enterTimers.forEach((timerId) => clearTimeout(timerId));
    enterTimers.clear();
    if(exitTimer){
      clearTimeout(exitTimer);
      exitTimer = null;
    }
  }

  function setRowShown(row){
    if(!row) return;
    row.classList.remove('point-enter', 'point-exit');
    row.style.removeProperty('--exit-delay');
    row.classList.add('point-shown');
  }

  function buildList(){
    listEl = root.querySelector('#points-list');
    if(!listEl) return;

    clearAnimationTimers();

    listEl.innerHTML = points.map((p, idx) => {
      const titleHtml = p.title ? '<strong>' + escapeHtml(p.title) + '</strong>' : '';
      const contentHtml = p.content ? '<span>' + escapeHtml(p.content) + '</span>' : '';
      return '<li class=\"point-item\" data-index=\"' + idx + '\">' + titleHtml + contentHtml + '</li>';
    }).join('');

    for(let i = 0; i < visibleCount; i += 1){
      setRowShown(listEl.children[i]);
    }
  }

  function revealNext(){
    if(!listEl) return;
    if(visibleCount >= points.length) return;

    const row = listEl.children[visibleCount];
    if(!row) return;

    row.classList.remove('point-shown', 'point-exit');
    row.style.removeProperty('--exit-delay');
    row.classList.add('point-enter');
    visibleCount += 1;

    const timerId = setTimeout(() => {
      row.classList.remove('point-enter');
      row.classList.add('point-shown');
      enterTimers.delete(timerId);
    }, 720);

    enterTimers.add(timerId);
  }

  function start(){
    revealNext();
  }

  function stop(){
    if(!listEl || visibleCount <= 0) return;

    clearAnimationTimers();

    const rows = Array.from(listEl.children).slice(0, visibleCount);
    rows.forEach((row, idx) => {
      row.classList.remove('point-enter', 'point-shown');
      row.style.setProperty('--exit-delay', (idx * 80) + 'ms');
      row.classList.add('point-exit');
    });

    const total = rows.length * 80 + 420;
    exitTimer = setTimeout(() => {
      rows.forEach((row) => {
        row.classList.remove('point-exit');
        row.style.removeProperty('--exit-delay');
      });
      visibleCount = 0;
      exitTimer = null;
    }, total);
  }

  function restart(){
    clearAnimationTimers();
    visibleCount = 0;
    if(!listEl) return;
    Array.from(listEl.children).forEach((row) => {
      row.classList.remove('point-enter', 'point-exit', 'point-shown');
      row.style.removeProperty('--exit-delay');
    });
  }

  function updateConfig(next){
    currentConfig = {...(next || {})};
    points = parsePoints(currentConfig);
    if(visibleCount > points.length){
      visibleCount = points.length;
    }
    buildList();
  }

  points = parsePoints(currentConfig);
  buildList();

  return {
    start,
    stop,
    restart,
    updateConfig,
    destroy: function(){
      clearAnimationTimers();
    }
  };
}
